    fun findById(id: String): IRDevice? = ALL_DEVICES.find { it.id == id }

    fun search(query: String): List<IRDevice> {
        if (query.isBlank()) return ALL_DEVICES
        val q = query.lowercase()
        return ALL_DEVICES.filter {
            it.brand.lowercase().contains(q) ||
            it.model.lowercase().contains(q) ||
            it.type.lowercase().contains(q)
        }
    }
